+    #[derive(Debug, Clone, PartialEq, Eq)]
+    struct CapturedTraceSpan {
+        name: String,
+        target: String,
+        fields: BTreeMap<String, String>,
+    }
+
+    #[derive(Default)]
+    struct CapturedTraceFields {
+        fields: BTreeMap<String, String>,
+    }
+
+    impl Visit for CapturedTraceFields {
+        fn record_i64(&mut self, field: &Field, value: i64) {
+            self.fields.insert(field.name().to_owned(), value.to_string());
+        }
+
+        fn record_u64(&mut self, field: &Field, value: u64) {
+            self.fields.insert(field.name().to_owned(), value.to_string());
+        }
+
+        fn record_bool(&mut self, field: &Field, value: bool) {
+            self.fields.insert(field.name().to_owned(), value.to_string());
+        }
+
+        fn record_str(&mut self, field: &Field, value: &str) {
+            self.fields.insert(field.name().to_owned(), value.to_owned());
+        }
+
+        fn record_debug(&mut self, field: &Field, value: &dyn std::fmt::Debug) {
+            self.fields
+                .insert(field.name().to_owned(), format!("{value:?}"));
+        }
+    }
+
+    #[derive(Clone, Default)]
+    struct TraceSpanCaptureLayer {
+        spans: Arc<std::sync::Mutex<Vec<CapturedTraceSpan>>>,
+    }
+
+    impl<S> tracing_subscriber::Layer<S> for TraceSpanCaptureLayer
+    where
+        S: tracing::Subscriber,
+    {
+        fn on_new_span(
+            &self,
+            attrs: &tracing::span::Attributes<'_>,
+            _id: &tracing::span::Id,
+            _ctx: tracing_subscriber::layer::Context<'_, S>,
+        ) {
+            let mut fields = CapturedTraceFields::default();
+            attrs.record(&mut fields);
+            self.spans
+                .lock()
+                .expect("trace span capture mutex poisoned")
+                .push(CapturedTraceSpan {
+                    name: attrs.metadata().name().to_owned(),
+                    target: attrs.metadata().target().to_owned(),
+                    fields: fields.fields,
+                });
+        }
+    }
